/**
 * @param {number} n
 * @param {number[][]} edges
 * @param {number} source
 * @param {number} target
 * @param {number} k
 * @return {number}
 */
function solve(n, edges, source, target, k) {
    if (source === target) {
        return 0;
    }

    const uniqueWeights = new Set([0]);
    for (const [, , w] of edges) {
        uniqueWeights.add(w);
    }

    const sortedWeights = Array.from(uniqueWeights).sort((a, b) => a - b);

    /**
     * Checks if a path exists from source to target using at most k heavy edges,
     * given a specific threshold.
     * @param {number} threshold
     * @returns {boolean}
     */
    function canReach(threshold) {
        // weights[i][j] = min number of heavy edges to reach j from i
        // Since we are only interested in reachability within k heavy edges,
        // we can use a modified BFS/Dijkstra where the state is (node, heavy_edge_count).
        // State space size: N * (K+1)

        // dist[i][j] stores the minimum number of heavy edges required to reach node i 
        // with exactly j heavy edges used so far.
        // We only need to check if dist[target][j] <= k for any j <= k.

        // Let dp[i][j] be true if node i is reachable using exactly j heavy edges.
        // This seems like a variation of BFS on an expanded state graph.

        // Let dist[i] be the minimum number of heavy edges required to reach node i.
        // We initialize dist[i] to Infinity, dist[source] = 0.
        // Priority queue stores [heavy_edge_count, node]

        const dist = new Array(n).fill(k + 1);
        dist[source] = 0;

        // Simple BFS since edge weights in the state space (0 or 1) are non-negative.
        const queue = [];
        queue.push(source);

        let head = 0;
        while (head < queue.length) {
            const u = queue[head++];
            const currentHeavyCount = dist[u];

            if (u === target) {
                // If we reached target, we know the minimum heavy count is <= k because we only push if count <= k
                // We don't need to return true immediately, as a path with fewer heavy edges might be found later
                // or we might need to explore more to confirm reachability if k was the constraint.
                // But since we are checking *existence*, if we reach it, we are done for this threshold.
                // However, standard BFS on the state space (node, heavy_count) is cleaner.
                // Since we are minimizing heavy_count, the first time we pop 'target' with count <= k, we are good.
                // Let's stick to the explicit state space if needed, but for simple reachability with a bound, Dijkstra/BFS on (node, count) works.
                if (currentHeavyCount <= k) {
                    // This check is redundant if we only push states where heavy_count <= k + 1 initially
                    // Let's rely on the relaxation below.
                }
            }


            // Build adjacency list specific to this threshold
            const neighbors = [];
            for (const [u_edge, v_edge, w_edge] of edges) {
                let u_adj = -1, v_adj = -1;
                if (u_edge === u) {
                    u_adj = v_edge;
                    v_adj = u_edge;
                } else if (v_edge === u) {
                    u_adj = u_edge;
                    v_adj = v_edge;
                } else {
                    continue; // Not connected to u
                }

                // Determine if the edge is heavy
                const isHeavy = w_edge > threshold ? 1 : 0;

                // Process both directions (since graph is undirected)
                const processNeighbor = (v_neighbor) => {
                    const newHeavyCount = currentHeavyCount + isHeavy;

                    if (newHeavyCount <= k) {
                        // If we found a path to v_neighbor with fewer heavy edges than previously recorded
                        if (newHeavyCount < dist[v_neighbor]) {
                            dist[v_neighbor] = newHeavyCount;
                            queue.push(v_neighbor);
                        }
                    }
                };

                // For undirected graph, both endpoints are neighbors
                processNeighbor(u_adj);
                processNeighbor(v_adj);
            }
        }

        return dist[target] <= k;
    }

    // Binary Search on the threshold
    let low = 0;
    let high = sortedWeights.length - 1;
    let minThreshold = -1;

    while (low <= high) {
        const midIndex = Math.floor((low + high) / 2);
        const currentThreshold = sortedWeights[midIndex];

        if (canReach(currentThreshold)) {
            // Possible, try a smaller threshold
            minThreshold = currentThreshold;
            high = midIndex - 1;
        } else {
            // Not possible, need a larger threshold (to make more edges light)
            low = midIndex + 1;
        }
    }

    return minThreshold;
}

