import (
	"container/list"
	"sort"
)

// Edge structure for convenience
type Edge struct {
	U, V, W int64
}

func solve(n int64, edges [][]int64, source int64, target int64, k int64) int64 {
	if source == target {
		return 0
	}

	// Collect unique weights and sort them
	weightSet := make(map[int64]bool)
	weightSet[0] = true // Include 0 as a potential minimum threshold
	for _, edge := range edges {
		weightSet[edge[2]] = true
	}

	uniqueWeights := make([]int64, 0, len(weightSet))
	for w := range weightSet {
		uniqueWeights = append(uniqueWeights, w)
	}
	sort.Slice(uniqueWeights, func(i, j int) bool {
		return uniqueWeights[i] < uniqueWeights[j]
	})

	// Adjacency list representation for easier graph traversal
	// adj[u] stores list of {v, weight}
	adj := make([][][2]int64, n)
	for _, edge := range edges {
		u, v, w := edge[0], edge[1], edge[2]
		adj[u] = append(adj[u], [2]int64{v, w})
		adj[v] = append(adj[v], [2]int64{u, w})
	}

	// canReach checks if a path exists from source to target using at most k heavy edges
	// given a specific threshold.
	canReach := func(threshold int64) bool {
		// dist[i] stores the minimum number of heavy edges required to reach node i.
		// Initialize to k + 1 (a value > k)
		dist := make([]int64, n)
		for i := range dist {
			dist[i] = k + 1
		}
		dist[source] = 0

		// Queue for BFS: stores node index
		queue := list.New()
		queue.PushBack(source)

		for queue.Len() > 0 {
			element := queue.Front()
			queue.Remove(element)
			u := element.Value.(int64)
			currentHeavyCount := dist[u]

			if u == target {
				// Since we use BFS style relaxation (shortest path in terms of heavy edges),
				// the first time we extract the target, it's via the minimum heavy edge path.
				return currentHeavyCount <= k
			}

			for _, neighborInfo := range adj[u] {
				v := neighborInfo[0]
				w := neighborInfo[1]

				// Determine if the edge is heavy
				isHeavy := int64(0)
				if w > threshold {
					isHeavy = 1
				}

				newHeavyCount := currentHeavyCount + isHeavy

				if newHeavyCount <= k {
					// Relaxation step: if we found a path to v with fewer heavy edges
					if newHeavyCount < dist[v] {
						dist[v] = newHeavyCount
						queue.PushBack(v)
					}
				}
			}
		}

		return dist[target] <= k
	}

	// Binary Search on the threshold among unique weights
	low := 0
	high := len(uniqueWeights) - 1
	minThreshold := int64(-1)

	for low <= high {
		midIndex := low + (high-low)/2
		currentThreshold := uniqueWeights[midIndex]

		if canReach(currentThreshold) {
			// Possible, record this threshold and try a smaller one
			minThreshold = currentThreshold
			high = midIndex - 1
		} else {
			// Not possible, need a larger threshold (to make more edges light)
			low = midIndex + 1
		}
	}

	return minThreshold
}
