// Priority Queue Item for Dijkstra's algorithm
type Item struct {
	node int64
	count int64 // Number of heavy edges used so far
}

// PriorityQueue implements heap.Interface and holds Items.
type PriorityQueue []*Item

func (pq PriorityQueue) Len() int { return len(pq) }

func (pq PriorityQueue) Less(i, j int) bool {
	// We want the item with the minimum heavy edge count
	return pq[i].count < pq[j].count
}

func (pq PriorityQueue) Swap(i, j int) {
	pq[i], pq[j] = pq[j], pq[i]
}

func (pq *PriorityQueue) Push(x interface{}) {
	item := x.(*Item)
	*pq = append(*pq, item)
}

func (pq *PriorityQueue) Pop() interface{} {
	old := *pq
	n := len(old)
	item := old[n-1]
	*pq = old[0 : n-1]
	return item
}

// canReach checks if a path exists from source to target using at most k heavy edges,
// given a specific threshold.
func canReach(n int64, edges []Edge, source int64, target int64, k int64, threshold int64) bool {
	if source == target {
		return true
	}

	// dist[i] stores the minimum number of heavy edges required to reach node i.
	// Initialize to k + 1 (which is greater than any allowed count k).
	dist := make([]int64, n)
	for i := range dist {
		dist[i] = k + 1
	}

	dist[source] = 0

	// Min-heap based on heavy edge count
	pq := make(PriorityQueue, 0)
	heap.Init(&pq)
	heap.Push(&pq, &Item{node: source, count: 0})

	for pq.Len() > 0 {
		item := heap.Pop(&pq).(*Item)
		u := item.node
		currentHeavyCount := item.count

		if currentHeavyCount > dist[u] {
			continue
		}

		if u == target {
			// Since we use Dijkstra-like approach (minimum heavy edges), 
			// if we reach target, the currentCount is the minimum possible heavy count.
			// Since we only push if newHeavyCount <= k, this must be <= k.
			return true
		}

		for _, edge := range edges {
			v := int64(-1)
			weight := edge.W
			isHeavy := int64(0)

			// Determine neighbor v and heavy status
			if edge.U == u {
				v = edge.V
			} else if edge.V == u {
				v = edge.U
			} else {
