	low := 0
	high := len(sortedWeights) - 1
	minThreshold := int64(-1)

	// We are looking for the smallest threshold such that canReach(threshold) is true.
	for low <= high {
		midIndex := low + (high-low)/2
		currentThreshold := sortedWeights[midIndex]

